"use strict";(self.webpackChunkejarzo_github_io=self.webpackChunkejarzo_github_io||[]).push([[876],{7549:function(e,t,n){var a=n(7294);t.Z=e=>{let{src:t,title:n,...r}=e;return a.createElement("div",{class:"iframe-container"},a.createElement("iframe",Object.assign({class:"responsive-iframe",frameborder:"0",src:t,title:n,allow:"autoplay; fullscreen",allowfullscreen:!0},r)))}},3391:function(e,t,n){n.r(t);var a=n(7294),r=n(1602),o=n(1082),i=n(3723),s=n(7549);t.default=()=>{const{bannerImage:e,schematic:t,boxImg:n}=(0,o.useStaticQuery)("3658146294");return a.createElement("div",null,a.createElement(r.Z,{title:"Puncture",description:"A collaborative performance with artist Marcel Yiran Wang using a custom-built musical interface",bannerImage:e,links:[{label:"Watch Performance",href:"https://vimeo.com/641689631"}],Content:()=>a.createElement("div",null,a.createElement("p",null,a.createElement("em",null,"Puncture")," is a collaboration with"," ",a.createElement("a",{href:"https://yiranwang.art/"},"Marcel Wang"),". It is a musical interface and performance that explores pressure, tension, and release."),a.createElement("p",null,a.createElement(s.Z,{title:"'Puncture' performance",src:"https://player.vimeo.com/video/641689631?color=eae6de"})),a.createElement("h3",null,"Background"),a.createElement("p",null,"This piece expands on Marcel's previous work entitled"," ",a.createElement("a",{href:"https://yiranwang.art/untitled"},a.createElement("em",null,"“ ”"))," ","that employs the distortion and crumpling of paper to reflect on emotional stress that cannot be undone. In her words:"),a.createElement("p",null,a.createElement("em",null,'The initial idea comes from my unfortunate experience when I was in senior school. The reason for the box is because it has a similar shape to the student locker in my school. It took me a long time to get rid of the shadow of the locker because something bad happened which deeply affected me at that time. The intention of the paper is pretty obvious as its materiality: easy to be broke and tortured which makes me feel it is fragile like a human being. Although it is from my personal experience, I don\'t want it to be "my personal" somehow. I didn\'t include any specific direction in either description and project title. I intend to encourage the audience to recall their own memories, some painful and broken moments in their own lives instead of thinking like "this is the experience of the artist, having nothing to do with me".')),a.createElement("p",null,"Our piece extends this theme into the sonic realm. The paper (and box) becomes the interface through which we create sound and music."),a.createElement("h3",null,"Concept"),a.createElement("p",null,a.createElement(i.G,{image:n.childImageSharp.gatsbyImageData,alt:"3D rendering of the box showing the paper face sandwiched in between the front rim of the box and the back"})),a.createElement("p",null,"The title ",a.createElement("em",null,"Puncture"),', or "cause a sudden collapse of (mood or feeling)", provides a blueprint for how we wanted the experience to feel. The words we used to describe the feeling were "uncomfortable, annoying, chaos, anxious, not beautiful". "You have to push it very carefully to touch the boundary and breaking point."'),a.createElement("p",null,a.createElement(i.G,{image:t.childImageSharp.gatsbyImageData,alt:"System diagram. Two boxes, each being recorded by two contact mics, connect to a computer. The first box has holes in the back through which pressure sensitive rods are inserted. Their pressure is used to generate sound"})),a.createElement("p",null,"Performing with this device involves exploring the paper's texture and resistance by inserting 'prods' into holes in the back of the box and pressing against the paper surface. From the front, the audience sees a paper sheet being poked and stretched from under the surface. The sound of the paper crinkling, stretching, and tearing is blended with synthesized and recorded audio that is modulated by the pressure being exerted on the different prods. The harder you press, the more intense the sound becomes until eventually you puncture the surface and are left with silence. Our performance also features a second box, an early prototype that we repurposed to create a duet. The second box is positioned flat on the table and is played like a percussion instrument, using the box frame and paper surface to create texture and rhythm."),a.createElement("h3",null,"Sound Design"),a.createElement("p",null,"The sound consists of a mixture of raw audio from the contact microphones and synthesized/recorded audio from Ableton Live. We use Max/MSP to map the pressure sensors to various parameters in Ableton. In addition to the raw pressure values, we also calculate the velocity and acceleration of the values. This allows us to explore many more sonic avenues than with just the raw values -- for example, quick presses affect the sound differently than long slow presses."))}))}}}]);
